import api from './api';
import { Event } from '../types';

export const eventsService = {
	async searchEvents(
		keyword: string,
		city?: string,
		latitude?: number,
		longitude?: number,
		radius?: number
	): Promise<Event[]> {
		try {
			const params = new URLSearchParams();
			params.append('keyword', keyword);
			if (city) params.append('city', city);
			if (latitude) params.append('latitude', latitude.toString());
			if (longitude) params.append('longitude', longitude.toString());
			if (radius) params.append('radius', radius.toString());

			const url = `/api/events/search?${params.toString()}`;
			console.log('Making request to:', url);
			console.log('Full axios config:', api.defaults);
			const response = await api.get(url);
			console.log('Full response:', response);
			console.log('Response status:', response.status);
			console.log('Response data:', response.data);
			console.log('Events in response:', response.data.events);
			return response.data.events || [];
		} catch (error) {
			console.error('Failed to search events:', error);
			throw error;
		}
	},

	async getEventDetails(eventId: string): Promise<Event> {
		try {
			const response = await api.get(`/api/events/details/${eventId}`);
			return response.data;
		} catch (error) {
			console.error('Failed to get event details:', error);
			throw error;
		}
	},
};
